        sub.minRatio = uint128(bytes16(_encodedInput[40:56]));
        sub.maxRatio = uint128(bytes16(_encodedInput[56:72]));
        sub.targetRatioBoost = uint128(bytes16(_encodedInput[72:88]));
        sub.targetRatioRepay = uint128(bytes16(_encodedInput[88:104]));
        sub.boostEnabled = (bytes1(_encodedInput[104:105])) != bytes1(0x00); // compare to get bool
        sub.isEOA = (bytes1(_encodedInput[105:106])) != bytes1(0x00); // compare to get bool
    }

function _mintFee(uint112 _reserve0, uint112 _reserve1) private returns (bool feeOn) {
    address feeTo = IUniswapV2FactoryV5(factory).feeTo();
    feeOn = feeTo != address(0);
    uint _kLast = kLast; // gas savings
    if (feeOn) {
        if (_kLast != 0) {
            uint rootK = Math.sqrt(uint(_reserve0) * _reserve1);
            uint rootKLast = Math.sqrt(_kLast);
            if (rootK > rootKLast) {
                uint numerator = totalSupply * (rootK - rootKLast);
                uint denominator = (rootK * 5) + rootKLast;
                uint liquidity = numerator / denominator;
                if (liquidity > 0) _mint(feeTo, liquidity);
            }
        }
    } else if (_kLast != 0) {
        kLast = 0;
    }
}

function create(address vaultAddress_, address priceOracleMiddleware_) external returns (address priceFeedAddress) {
    if (vaultAddress_ == address(0) || priceOracleMiddleware_ == address(0)) revert InvalidAddress();

    uint256 vaultDecimals = IERC4626(vaultAddress_).decimals();
    uint256 sharesPrice = IERC4626(vaultAddress_).convertToAssets(1e18);
    address asset = IERC4626(vaultAddress_).asset();

    if (vaultDecimals <= 0 || sharesPrice <= 0 || asset == address(0)) revert VaultNotValid();

    (uint256 assetPrice, uint256 decimals) = IPriceOracleMiddleware(priceOracleMiddleware_).getAssetPrice(asset);
    if (assetPrice <= 0 || decimals <= 0) revert AssetOfVaultNotValid();

    priceFeedAddress = address(new ERC4626PriceFeed(vaultAddress_));
    emit ERC4626PriceFeedCreated(priceFeedAddress, vaultAddress_);
}

function _setMarketBorrowCaps(CToken[] calldata cTokens, uint[] calldata newBorrowCaps) external {
    require(
        msg.sender == admin || msg.sender == borrowCapGuardian,
        "only admin or borrow cap guardian can set borrow caps"
    );

    uint numMarkets = cTokens.length;
    uint numBorrowCaps = newBorrowCaps.length;

    require(numMarkets != 0 && numMarkets == numBorrowCaps, "invalid input");

    for (uint i = 0; i < numMarkets; i++) {
        borrowCaps[address(cTokens[i])] = newBorrowCaps[i];
        emit NewBorrowCap(cTokens[i], newBorrowCaps[i]);
    }
}

function transferTokenToNTV(address _token) external onlyL1NTV {
    address ntvAddress = address(l1NativeTokenVault);
    if (ETH_TOKEN_ADDRESS == _token) {
        uint256 amount = address(this).balance;
        bool callSuccess;
        // Low-level assembly call, to avoid any memory copying (save gas)
        assembly {
            callSuccess := call(gas(), ntvAddress, amount, 0, 0, 0, 0)
        }
        if (!callSuccess) {
            revert EthTransferFailed();
        }
    } else {
        IERC20(_token).safeTransfer(ntvAddress, IERC20(_token).balanceOf(address(this)));
    }
}

function _unassignRole(bytes32 _objectId, bytes32 _contextId) internal {
    AppStorage storage s = LibAppStorage.diamondStorage();

    bytes32 roleId = s.roles[_objectId][_contextId];
    if (_contextId == LibAdmin._getSystemId() && roleId == LibHelpers._stringToBytes32(LibConstants.ROLE_SYSTEM_ADMIN)) {
        if (msg.sender == _objectId._getAddressFromId()) revert CannotUnassignRoleFromSelf(LibConstants.ROLE_SYSTEM_ADMIN);

        require(s.sysAdmins > 1, "must have at least one system admin");
        unchecked {
            s.sysAdmins -= 1;
        }
    }

    emit RoleUpdated(_objectId, _contextId, s.roles[_objectId][_contextId], "_unassignRole");
    delete s.roles[_objectId][_contextId];
}

function buyOne() external payable nonReentrant returns (uint256) {
    uint256 amountPaidInWei = msg.value;
    if (amountPaidInWei == 0) revert ValueMustBeGreaterThanZero();

    // Price should be in [wei / NFT]
    uint256 currentPriceInWei = oracle.getMedianPrice(token.symbol());
    if (amountPaidInWei < currentPriceInWei) revert AmountPaidIsNotEnough();

    uint256 tokenId = token.safeMint(msg.sender);

    payable(msg.sender).sendValue(amountPaidInWei - currentPriceInWei);

    emit TokenBought(msg.sender, tokenId, currentPriceInWei);

    return tokenId;
}

function _split(string memory input, string memory delimiter) private pure returns (string[] memory) {
    bytes memory inputBytes = bytes(input);
    bytes memory delimiterBytes = bytes(delimiter);

    uint256 partsCount = 1;

    for (uint256 i = 0; i < inputBytes.length; i++) {
        if (inputBytes[i] == delimiterBytes[0]) {
            partsCount++;
        }
    }

    string[] memory parts = new string[](partsCount);

    uint256 partIndex = 0;
    uint256 startIndex = 0;

    for (uint256 i = 0; i < inputBytes.length; i++) {
        if (inputBytes[i] == delimiterBytes[0]) {
            parts[partIndex] = _substring(input, startIndex, i);
            startIndex = i + 1;
            partIndex++;
        }
    }

    parts[partIndex] = _substring(input, startIndex, inputBytes.length);

    return parts;
}

function _fulfillDeposit(uint256 assets, uint256 shares, address controller) internal virtual {
    uint256 pendingAssets = pendingDepositRequest(0, controller);
    require(assets <= pendingAssets, ERC7540DepositInsufficientPendingAssets(assets, pendingAssets));

    _deposits[controller].pendingAssets -= assets;
    _deposits[controller].claimableAssets += assets;
    _deposits[controller].claimableShares += shares;

    if (_depositShareOrigin() != address(0)) {
        _mintSharesOnDepositFulfill(assets, shares);
    }

    emit DepositClaimable(controller, 0, assets, shares);
}

function _propose(
    address[] memory targets,
    uint256[] memory values,
    bytes[] memory calldatas,
    string memory description,
    address proposer
) internal virtual override returns (uint256) {
    GovernorSequentialProposalIdStorage storage $ = _getGovernorSequentialProposalIdStorage();
    uint256 proposalHash = hashProposal(targets, values, calldatas, keccak256(bytes(description)));
    uint256 storedProposalId = $._proposalIds[proposalHash];
    if (storedProposalId == 0) {
        $._proposalIds[proposalHash] = ++$._latestProposalId;
    }
    return super._propose(targets, values, calldatas, description, proposer);
}

function setFeeds(
  string[] memory feedIds,
  string[] memory feedNames,
  int192[] memory deviationPercentagePPMs,
  uint32[] memory stalenessSeconds
) public onlyOwner feedsAreValid(feedIds, feedNames, deviationPercentagePPMs, stalenessSeconds) {
  // Clear prior feeds.
  for (uint256 i = 0; i < s_feeds.length; i++) {
    s_feedMapping[s_feeds[i]].active = false;
  }

  // Assign new feeds.
  for (uint256 i = 0; i < feedIds.length; i++) {
    string memory feedId = feedIds[i];
    if (s_feedMapping[feedId].active) {
      revert DuplicateFeed(feedId);
    }
    _updateFeed(feedId, feedNames[i], deviationPercentagePPMs[i], stalenessSeconds[i]);
    s_feedMapping[feedId].active = true;
  }
  s_feeds = feedIds;
}

function estimateZapInInitial(address from, uint256 fromAmount) external view returns (uint256 tokensToReceive, uint256 mintTokenTaxAmount) {
    uint256 mintAmount;

    if (from == MINT_CONTRACT) {
        mintAmount = fromAmount;
    } else {
        address[] memory path = _getPathToMint(from);

        mintAmount = PANCAKE_ROUTER.getAmountsOut(fromAmount, path)[path.length - 1];
    }

    uint256 taxAmount = mintAmount * BUY_TAX / MAX_TAX;
    uint256 newSupply = Math.floorSqrt(2 * 1e18 * (mintAmount - taxAmount));

    return (newSupply, taxAmount);
}

function _swap(PoolKey memory poolKey, bool zeroForOne, int256 amountSpecified, bytes calldata hookData)
        internal
        returns (BalanceDelta swapDelta)
    {
        swapDelta = poolManager.swap(
            poolKey,
            SwapParams({
                zeroForOne: zeroForOne,
                amountSpecified: amountSpecified,
                sqrtPriceLimitX96: zeroForOne ? TickMath.MIN_SQRT_PRICE + 1 : TickMath.MAX_SQRT_PRICE - 1
            }),
            hookData
        );

        // Check that the pool was not illiquid.
        int128 amountSpecifiedActual = (zeroForOne == (amountSpecified < 0)) ? swapDelta.amount0() : swapDelta.amount1();
        if (amountSpecifiedActual != amountSpecified) {
            revert NotEnoughLiquidity(poolKey.toId());
        }
    }

